											     class="mono s-small uppercase <?= $language->code() === kirby()->language()->code() ? 'lang-active' : '' ?>">
											    <?= $language->code() ?>
											  </a>
											<?php endforeach ?>
										</li>
									<?php endif; ?>
							  </ul>
							</nav>
